import pytest

class TestUserLogin:
 @pytest.fixture
 def setup(self):
 # Setup test data
 self.user = {"username": "testuser", "password": "pass123"}
 yield
 # Teardown
 pass

 def test_successful_login(self, setup):
 result = login(self.user["username"], self.user["password"])
 assert result.status_code == 200
 assert result.json()["token"] is not None

 def test_invalid_password(self, setup):
 result = login(self.user["username"], "wrongpass")
 assert result.status_code == 401

 def test_missing_username(self):
 result = login("", "pass123")
 assert result.status_code == 400

if __name__ == "__main__":
 pytest.main(["-v", "test_login.py"])
